import app from 'flarum/forum/app';
import Component from 'flarum/common/Component';
import Link from 'flarum/common/components/Link';
import { cc } from '../render';
/**
 * The guild-forum character pane shown in a post's side column: the author's
 * main character render, name in class color, race/spec line, level + item
 * level, and guild tag. Data comes from the `armoryMain` user attribute —
 * no extra requests. Purely presentational; themes are expected to skin it.
 */
export default class ArmoryPostPane extends Component {
  view() {
    const c = this.attrs.main;
    const color = cc(c.class || '');
    const img = c.renderUrl || c.avatarUrl;
    const specLine = [c.race, [c.spec, c.class].filter(Boolean).join(' ')].filter(s => s && String(s).trim()).join(' · ');
    return m("div", {
      className: "ArmoryPostPane",
      style: color !== 'inherit' ? {
        '--ar-class': color
      } : undefined
    }, m(Link, {
      href: app.route('armory'),
      className: "ArmoryPostPane-frame",
      title: c.name
    }, img ? m("img", {
      src: img,
      alt: c.name,
      loading: "lazy",
      className: c.renderUrl ? 'is-render' : 'is-avatar'
    }) : m("span", {
      className: "ArmoryPostPane-noimg",
      "aria-hidden": "true"
    }, m("i", {
      className: "fas fa-user-shield"
    }))), m("span", {
      className: "ArmoryPostPane-name",
      style: color !== 'inherit' ? {
        color
      } : undefined
    }, c.name), specLine ? m("span", {
      className: "ArmoryPostPane-spec"
    }, specLine) : null, m("span", {
      className: "ArmoryPostPane-ilvl"
    }, app.translator.trans('ernestdefoe-armory.forum.pane_level_ilvl', {
      level: c.level,
      ilvl: c.itemLevel
    })), c.guild ? m("span", {
      className: "ArmoryPostPane-guild"
    }, '<' + c.guild + '>') : null);
  }
}
flarum.reg.add('ernestdefoe-armory', 'forum/components/ArmoryPostPane', ArmoryPostPane);